SELECT 
 { [Measures].[rolling-2 years], [Measures].[Internet Order Count] }  ON COLUMNS, 
  SUBSET( Hierarchize(  { [DateCustom].[StandardMonth].[Year].Members, [DateCustom].[StandardMonth].[Quarter].Members, Hierarchize(
  DrilldownMember( 
 {     DrilldownLevel( { [DateCustom].[StandardMonth].[All] } )
   } ,

 {     [DateCustom].[StandardMonth].[Year].&[2005-01-01T00:00:00]
   } 
  )) }  )  , 0, 300)DIMENSION PROPERTIES HIERARCHY_UNIQUE_NAME, PARENT_UNIQUE_NAME ON ROWS 
  FROM [ASAdventureSmall]

